                    pm.expect(json).to.have.property('toolCalls');
                    pm.expect(json.toolCalls).to.be.an('array');
                });

                if (json.toolCalls.length > 0) {
                    pm.test("Each tool call has a valid tool type", () => {
                        const validTools = ['add_question', 'edit_question', 'remove_question', 'reorder_questions'];
                        json.toolCalls.forEach((call, i) => {
                            pm.expect(call, `toolCalls[${i}]`).to.have.property('tool');
                            pm.expect(validTools, `toolCalls[${i}].tool`).to.include(call.tool);
                        });
                    });

                    pm.test("add_question tool calls have valid shape", () => {
                        json.toolCalls
                            .filter(c => c.tool === 'add_question')
                            .forEach((call, i) => {
                                pm.expect(call, `add_question[${i}]`).to.have.property('question');
                                pm.expect(call.question.type).to.be.oneOf(['multiple-choice', 'multiple-select-choice']);
                                pm.expect(call.question.question).to.be.a('string').and.not.empty;
                                pm.expect(call.question.answer).to.be.an('array').with.lengthOf(4);
                                pm.expect(call.question.correctAnswers).to.be.an('array').with.length.above(0);
                                if (call.question.time !== undefined) {
                                    pm.expect(call.question.time).to.be.within(1, 60);
                                }
                            });
                    });

                    pm.test("edit_question tool calls have valid shape", () => {
                        json.toolCalls
                            .filter(c => c.tool === 'edit_question')
                            .forEach((call, i) => {
                                pm.expect(call, `edit_question[${i}]`).to.have.property('order');
                                pm.expect(call.order).to.be.a('number').and.least(0);
                                pm.expect(call, `edit_question[${i}]`).to.have.property('patch');
                                pm.expect(call.patch).to.be.an('object');
                            });
                    });

                    pm.test("remove_question tool calls have valid shape", () => {
                        json.toolCalls
                            .filter(c => c.tool === 'remove_question')
                            .forEach((call, i) => {
                                pm.expect(call, `remove_question[${i}]`).to.have.property('order');
                                pm.expect(call.order).to.be.a('number').and.least(0);
                            });
                    });

                    pm.test("reorder_questions tool calls have valid shape", () => {
                        json.toolCalls
                            .filter(c => c.tool === 'reorder_questions')
                            .forEach((call, i) => {
                                pm.expect(call, `reorder_questions[${i}]`).to.have.property('newOrder');
                                pm.expect(call.newOrder).to.be.an('array').with.length.above(0);
                                call.newOrder.forEach((idx, j) => {
                                    pm.expect(idx, `newOrder[${j}]`).to.be.a('number').and.least(0);
                                });
                            });
